<template>
  <q-layout view="lHh Lpr lFf" class="affiliate-app">
    <q-page-container><q-page class="affiliate-app__page"><div class="affiliate-app__shell">
      <header class="affiliate-app__header"><router-link class="affiliate-app__brand" to="/"><img src="/favicon.png" alt="" /><span>AITO<span>SOFTWARES</span></span></router-link><div class="affiliate-app__session"><q-btn flat round icon="mdi-bell-outline" aria-label="Notificações" @click="notificationsOpen = true"><q-badge v-if="unread" color="secondary" floating>{{ unread }}</q-badge></q-btn><div><strong>{{ firstName }}</strong><small>{{ affiliate.email }}</small></div><q-btn flat round icon="mdi-logout" aria-label="Sair" @click="logout"><q-tooltip>Sair</q-tooltip></q-btn></div></header>
      <nav class="affiliate-app__nav"><button v-for="item in menu" :key="item.id" type="button" :class="{ 'is-active': activeMenu === item.id }" @click="activeMenu = item.id"><q-icon :name="item.icon" /> {{ item.label }}</button></nav>
      <main v-if="activeMenu === 'overview'" class="affiliate-app__main"><span class="affiliate-app__eyebrow">Área do afiliado</span><h1>Venda com contexto. Acompanhe cada resultado.</h1><div class="affiliate-app__stats"><section><small>Saldo disponível</small><strong>R$ {{ money(balance.available) }}</strong></section><section><small>Compras confirmadas</small><strong>{{ summary.purchases || 0 }}</strong></section><section><small>Cupons ativos</small><strong>{{ summary.coupons || 0 }}</strong></section></div></main>
      <main v-else-if="activeMenu === 'coupons'" class="affiliate-app__main"><span class="affiliate-app__eyebrow">Cupons vinculados</span><h2>Seus códigos</h2><div class="affiliate-app__list"><article v-for="coupon in coupons" :key="coupon._id"><strong>{{ coupon.title }}</strong><span>{{ coupon.description || 'Cupom monitorado pela AitoSoftwares.' }}</span><small>Desconto: R$ {{ money(coupon.discountAmount) }} · {{ coupon.usageCount || 0 }} usos</small></article><p v-if="!coupons.length">Nenhum cupom vinculado ainda.</p></div></main>
      <main v-else-if="activeMenu === 'sales'" class="affiliate-app__main"><span class="affiliate-app__eyebrow">Compras atribuídas</span><h2>Seu impacto</h2><div class="affiliate-app__table"><div v-for="purchase in purchases" :key="purchase._id"><strong>{{ purchase.course?.title || 'Curso' }}</strong><span>{{ purchase.couponCode || 'Sem código' }} · {{ new Date(purchase.paidAt || purchase.createdAt).toLocaleString('pt-BR') }}</span><b>R$ {{ money(purchase.commissionAmount) }}</b></div><p v-if="!purchases.length">Ainda não há compras confirmadas.</p></div></main>
      <main v-else-if="activeMenu === 'withdrawals'" class="affiliate-app__main"><span class="affiliate-app__eyebrow">Saques</span><h2>Receba suas comissões</h2><q-form class="affiliate-app__form" @submit.prevent="requestWithdrawal"><q-input v-model.number="withdrawalAmount" outlined type="number" min="50" step="0.01" label="Valor do saque" prefix="R$" /><q-input v-model="withdrawalDescription" outlined type="textarea" label="Observação (opcional)" /><q-btn unelevated no-caps type="submit" icon="mdi-bank-transfer-out" label="Solicitar saque" :loading="loading" /></q-form><div class="affiliate-app__table"><div v-for="item in withdrawals" :key="item._id"><strong>{{ item.title }}</strong><span>{{ item.status }} · {{ new Date(item.createdAt).toLocaleDateString('pt-BR') }}</span><b>R$ {{ money(item.amount) }}</b></div></div></main>
      <main v-else class="affiliate-app__main"><span class="affiliate-app__eyebrow">Meu perfil</span><h2>Seu perfil de parceiro</h2><q-form class="affiliate-app__form" @submit.prevent="saveProfile"><q-input v-model="profile.name" outlined label="Nome" /><q-input v-model="profile.email" outlined label="E-mail" readonly /><q-input v-model="profile.instagram" outlined label="Instagram" /><q-input v-model="profile.tiktok" outlined label="TikTok" /><q-input v-model="profile.youtube" outlined label="YouTube" /><q-btn unelevated no-caps type="submit" icon="mdi-content-save" label="Salvar perfil" :loading="loading" /></q-form></main>
    </div></q-page></q-page-container>
    <q-dialog v-model="notificationsOpen"><q-card class="affiliate-app__dialog"><q-card-section><div class="row items-center justify-between"><strong>Notificações</strong><q-btn flat round icon="mdi-close" v-close-popup /></div></q-card-section><q-card-section><article v-for="item in notifications" :key="item._id" class="affiliate-app__notice" :class="{ 'is-unread': !item.read }" @click="markRead(item)"><strong>{{ item.title }}</strong><span>{{ item.message }}</span></article><p v-if="!notifications.length">Nenhuma notificação.</p></q-card-section></q-card></q-dialog>
  </q-layout>
</template>

<script setup>
import { computed, onMounted, reactive, ref } from 'vue'
import { useQuasar } from 'quasar'
import { useRouter } from 'vue-router'
import { api } from 'boot/axios'

const router = useRouter(); const $q = useQuasar(); const token = localStorage.getItem('aito_affiliate_token'); const headers = { headers: { Authorization: `Bearer ${token}` } }
const affiliate = ref({}); const summary = ref({}); const balance = ref({ available: 0 }); const coupons = ref([]); const purchases = ref([]); const withdrawals = ref([]); const notifications = ref([]); const notificationsOpen = ref(false); const loading = ref(false); const withdrawalAmount = ref(null); const withdrawalDescription = ref(''); const activeMenu = ref('overview'); const profile = reactive({ name: '', email: '', instagram: '', tiktok: '', youtube: '' })
const menu = [{ id: 'overview', label: 'Resumo', icon: 'mdi-view-dashboard-outline' }, { id: 'coupons', label: 'Meus cupons', icon: 'mdi-ticket-percent-outline' }, { id: 'sales', label: 'Compras', icon: 'mdi-chart-line' }, { id: 'withdrawals', label: 'Saques', icon: 'mdi-bank-transfer-out' }, { id: 'profile', label: 'Meu perfil', icon: 'mdi-account-outline' }]; const firstName = computed(() => String(affiliate.value.name || 'Afiliado Aito').split(/\s+/)[0]); const unread = computed(() => notifications.value.filter((item) => !item.read).length)
function money(value) { return Number(value || 0).toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }) }
async function load() { try { const [me, couponResponse, purchaseResponse, withdrawalResponse, notificationResponse] = await Promise.all([api.get('/affiliate/me', headers), api.get('/affiliate/coupons', headers), api.get('/affiliate/purchases', headers), api.get('/affiliate/withdrawals', headers), api.get('/affiliate/notifications', headers)]); affiliate.value = me.data.data.affiliate; balance.value = me.data.data.balance; Object.assign(profile, affiliate.value); coupons.value = couponResponse.data.data || []; purchases.value = purchaseResponse.data.data || []; withdrawals.value = withdrawalResponse.data.data || []; notifications.value = notificationResponse.data.data || []; summary.value = (await api.get('/affiliate/summary', headers)).data.data } catch (error) { $q.notify({ type: 'negative', message: error.response?.data?.message || 'Não foi possível carregar a área do afiliado.' }) } }
async function saveProfile() { loading.value = true; try { const response = await api.put('/affiliate/me', profile, headers); affiliate.value = response.data.data; $q.notify({ type: 'positive', message: 'Perfil atualizado.' }) } finally { loading.value = false } }
async function requestWithdrawal() { loading.value = true; try { await api.post('/affiliate/withdrawals', { amount: withdrawalAmount.value, description: withdrawalDescription.value }, headers); withdrawalAmount.value = null; withdrawalDescription.value = ''; await load(); $q.notify({ type: 'positive', message: 'Solicitação de saque enviada.' }) } catch (error) { $q.notify({ type: 'negative', message: error.response?.data?.message || 'Não foi possível solicitar o saque.' }) } finally { loading.value = false } }
async function markRead(item) { if (item.read) return; await api.patch(`/affiliate/notifications/${item._id}/read`, {}, headers); item.read = true }
function logout() { localStorage.removeItem('aito_affiliate_token'); localStorage.removeItem('aito_affiliate_user'); router.push('/') }
onMounted(load)
</script>

<style scoped>
.affiliate-app { color: #effffb; background: #03090b; }.affiliate-app__page { min-height: 100vh; background: radial-gradient(circle at 70% 15%, rgba(19,188,157,.14), transparent 28rem), linear-gradient(rgba(19,188,157,.045) 1px, transparent 1px), linear-gradient(90deg, rgba(19,188,157,.04) 1px, transparent 1px), #03090b; background-size: auto, 72px 72px, 72px 72px, auto; }.affiliate-app__shell { width: min(1180px, calc(100% - 2rem)); margin: auto; }.affiliate-app__header { display:flex; align-items:center; justify-content:space-between; padding:1rem 0; border-bottom:1px solid rgba(19,188,157,.2); }.affiliate-app__brand { display:flex; align-items:center; gap:.6rem; color:#effffb; font-weight:900; letter-spacing:.12em; text-decoration:none; }.affiliate-app__brand img { width:34px; height:34px; }.affiliate-app__brand span span { color:#13bc9d; }.affiliate-app__session { display:flex; align-items:center; gap:.6rem; }.affiliate-app__session>div { display:grid; text-align:right; }.affiliate-app__session small { color:rgba(239,255,251,.55); font-size:.65rem; }.affiliate-app__nav { display:flex; flex-wrap:wrap; gap:.4rem; padding:1.1rem 0; border-bottom:1px solid rgba(19,188,157,.14); }.affiliate-app__nav button { display:inline-flex; align-items:center; gap:.4rem; padding:.55rem .75rem; border:1px solid rgba(19,188,157,.25); border-radius:.5rem; color:rgba(239,255,251,.7); background:rgba(3,25,26,.5); cursor:pointer; font:inherit; font-size:.72rem; }.affiliate-app__nav button.is-active { color:#03110f; background:linear-gradient(135deg,#8fffee,#13bc9d); }.affiliate-app__main { padding:8vh 0; }.affiliate-app__eyebrow { color:#8fffee; font-size:.7rem; font-weight:900; letter-spacing:.15em; text-transform:uppercase; }.affiliate-app h1 { max-width:12ch; margin:.8rem 0 2.8rem; font-size:clamp(2.5rem,6vw,5.5rem); line-height:.96; background:linear-gradient(135deg,#effffb,#13bc9d,#8fffee); background-clip:text; -webkit-background-clip:text; color:transparent; }.affiliate-app h2 { font-size:clamp(2rem,4vw,3.6rem); }.affiliate-app__stats { display:grid; grid-template-columns:repeat(3,1fr); gap:.8rem; }.affiliate-app__stats section,.affiliate-app__list article,.affiliate-app__table>div { display:grid; gap:.4rem; padding:1.1rem; border:1px solid rgba(19,188,157,.25); border-radius:.7rem; background:rgba(4,24,25,.72); }.affiliate-app__stats small,.affiliate-app__list span,.affiliate-app__table span { color:rgba(239,255,251,.58); font-size:.74rem; }.affiliate-app__stats strong,.affiliate-app__table b { color:#8fffee; font-size:1.2rem; }.affiliate-app__list { display:grid; gap:.7rem; max-width:720px; }.affiliate-app__form { display:grid; max-width:560px; gap:.8rem; margin:2rem 0; }.affiliate-app__form :deep(.q-field__control) { color:#effffb; background:rgba(4,24,25,.78); }.affiliate-app__form :deep(.q-field__native),.affiliate-app__form :deep(.q-field__label) { color:rgba(239,255,251,.82); }.affiliate-app__form .q-btn { width:max-content; color:#03110f; background:linear-gradient(135deg,#8fffee,#13bc9d); font-weight:800; }.affiliate-app__table { display:grid; gap:.6rem; max-width:900px; }.affiliate-app__notice { display:grid; gap:.35rem; padding:.75rem; border-bottom:1px solid rgba(19,188,157,.14); cursor:pointer; }.affiliate-app__notice span { color:rgba(239,255,251,.66); font-size:.76rem; }.affiliate-app__notice.is-unread { border-left:3px solid #13bc9d; }.affiliate-app__dialog { width:min(92vw,32rem); color:#effffb; background:#041819; }
@media (max-width:700px) { .affiliate-app__stats { grid-template-columns:1fr; }.affiliate-app__session>div { display:none; } }
</style>
